package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.charset.StandardCharsets
import java.nio.file.{Files, Path, Paths}
import scala.util.Using

@Singleton
class UserFilesController @Inject() (cc: ControllerComponents) extends AbstractController(cc) {

  private val uploadsRoot: Path = Paths.get("uploads").toAbsolutePath.normalize

  def getFile(filename: String): Action[AnyContent] = Action { implicit request =>
    val relative = filename.replace('\\', '/').stripPrefix("/")

    if (relative.isEmpty) {
      BadRequest("Missing filename")
    } else {
      val resolved = uploadsRoot.resolve(relative).normalize

      if (!resolved.startsWith(uploadsRoot)) {
        Forbidden("Invalid path")
      } else if (!Files.exists(resolved) || !Files.isRegularFile(resolved)) {
        NotFound("File not found")
      } else {
        try {
          val bytes = Using.resource(Source.fromFile(resolved.toFile, StandardCharsets.UTF_8.name())) { src =>
            src.mkString.getBytes(StandardCharsets.UTF_8)
          }
          Ok(bytes).as("application/octet-stream")
        } catch {
          case _: java.io.FileNotFoundException => NotFound("File not found")
          case _: SecurityException             => Forbidden("Access denied")
          case _: Throwable                     => InternalServerError("Error reading file")
        }
      }
    }
  }
}